import{_ as a,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Licencia: Explicación de Términos BSL | Plannotator","description":"Aprende sobre los términos de la licencia Business Source License 1.1 (BSL) de Plannotator y las restricciones de uso comercial. Conoce los escenarios de uso permitidos, los planes de cambio futuros y el calendario de conversión a Apache 2.0 en 2030.","frontmatter":{"title":"Licencia: Explicación de Términos BSL | Plannotator","sidebarTitle":"Comprender las Reglas de Uso Comercial","subtitle":"Licencia: Explicación de Términos BSL","description":"Aprende sobre los términos de la licencia Business Source License 1.1 (BSL) de Plannotator y las restricciones de uso comercial. Conoce los escenarios de uso permitidos, los planes de cambio futuros y el calendario de conversión a Apache 2.0 en 2030.","tags":["Licencia","BSL-1.1","Uso Comercial"],"prerequisite":[],"order":3},"headers":[],"relativePath":"es/backnotprop/plannotator/appendix/license/index.md","filePath":"es/backnotprop/plannotator/appendix/license/index.md"}'),t={name:"es/backnotprop/plannotator/appendix/license/index.md"};function n(s,e,c,l,d,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="explicacion-de-la-licencia-de-plannotator" tabindex="-1">Explicación de la Licencia de Plannotator <a class="header-anchor" href="#explicacion-de-la-licencia-de-plannotator" aria-label="Permalink to &quot;Explicación de la Licencia de Plannotator&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que Aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que Aprenderás&quot;">​</a></h2><ul><li>Comprender el tipo de licencia y los términos principales que utiliza Plannotator</li><li>Identificar claramente qué escenarios de uso están permitidos y cuáles están restringidos</li><li>Conocer el calendario de cambios futuros de la licencia</li><li>Saber cómo obtener una licencia comercial o contactar al licenciante</li></ul><h2 id="lo-que-necesitas-saber-ahora" tabindex="-1">Lo que Necesitas Saber Ahora <a class="header-anchor" href="#lo-que-necesitas-saber-ahora" aria-label="Permalink to &quot;Lo que Necesitas Saber Ahora&quot;">​</a></h2><p>Plannotator adopta la <strong>Business Source License 1.1 (BSL)</strong> como su licencia de código abierto. Esta es una licencia especial diseñada para proteger el valor comercial mientras eventualmente hace que el proyecto sea completamente de código abierto.</p><h2 id="terminos-principales" tabindex="-1">Términos Principales <a class="header-anchor" href="#terminos-principales" aria-label="Permalink to &quot;Términos Principales&quot;">​</a></h2><h3 id="tipo-de-licencia" tabindex="-1">Tipo de Licencia <a class="header-anchor" href="#tipo-de-licencia" aria-label="Permalink to &quot;Tipo de Licencia&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Elemento</th><th>Contenido</th></tr></thead><tbody><tr><td><strong>Nombre de la Licencia</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>Titular de los Derechos</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>Proyecto Licenciado</strong></td><td>plannotator</td></tr><tr><td><strong>Fecha de Cambio</strong></td><td>2030-01-01</td></tr><tr><td><strong>Licencia Posterior al Cambio</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">¿Qué es BSL?</p><p>Business Source License es una licencia especial desarrollada por MariaDB. Restringe ciertos usos comerciales a corto plazo, pero promete convertir el software en una licencia completamente de código abierto (como Apache 2.0) en una fecha específica. Este modelo permite que los proyectos de código abierto obtengan ingresos sostenibles durante el proceso de comercialización, al tiempo que garantiza la apertura a largo plazo para la comunidad.</p></div><h3 id="usos-permitidos" tabindex="-1">Usos Permitidos <a class="header-anchor" href="#usos-permitidos" aria-label="Permalink to &quot;Usos Permitidos&quot;">​</a></h3><p>Según los términos de BSL 1.1, puedes:</p><ul><li><p>✅ <strong>Copiar, modificar y crear obras derivadas</strong></p><ul><li>Puedes realizar desarrollo secundario basado en Plannotator</li><li>Puedes modificar el código fuente para adaptarlo a tus necesidades</li></ul></li><li><p>✅ <strong>Redistribuir</strong></p><ul><li>Puedes distribuir versiones originales o modificadas</li><li>Debes conservar la declaración de licencia original</li></ul></li><li><p>✅ <strong>Uso en Entornos No Productivos</strong></p><ul><li>Desarrollo interno, pruebas y evaluación</li><li>Aprendizaje personal e investigación</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">Uso Extensivo Personal y Empresarial Interno</p><p>BSL define &quot;uso en entornos no productivos&quot; de manera amplia, incluyendo varios escenarios personales y dentro de la empresa. Tú y los miembros de tu equipo (incluidos contratistas independientes) pueden usar Plannotator libremente para desarrollo, pruebas y despliegue.</p></div><h3 id="restricciones-de-uso-¡importante" tabindex="-1">Restricciones de Uso (¡Importante!) <a class="header-anchor" href="#restricciones-de-uso-¡importante" aria-label="Permalink to &quot;Restricciones de Uso (¡Importante!)&quot;">​</a></h3><p><strong>Restricción Principal</strong>: No se permite usar Plannotator para <strong>servicios de Planificación, Contexto o Aprobación (Planning, Context, or Approval Service)</strong>.</p><h4 id="¿que-son-los-servicios-de-planificacion-contexto-o-aprobacion" tabindex="-1">¿Qué son los &quot;Servicios de Planificación, Contexto o Aprobación&quot;? <a class="header-anchor" href="#¿que-son-los-servicios-de-planificacion-contexto-o-aprobacion" aria-label="Permalink to &quot;¿Qué son los &quot;Servicios de Planificación, Contexto o Aprobación&quot;?&quot;">​</a></h4><p>Cualquier producto comercial que permita a <strong>terceros</strong> (distintos de empleados y contratistas independientes) acceder a las funciones de Plannotator mediante operaciones directas o indirectas se considera un servicio restringido. Esto incluye específicamente, pero no se limita a:</p><ul><li><p><strong>Proveedores de Servicios en la Nube</strong></p><ul><li>Plataformas SaaS que ofrecen funciones de Plannotator como parte de sus servicios</li><li>Proveedores de servicios gestionados que ofrecen Plannotator a clientes o suscriptores</li></ul></li><li><p><strong>Servicios de Infraestructura</strong></p><ul><li>Proveedores de servicios de centros de datos</li><li>Proveedores de plataformas de computación en la nube</li></ul></li><li><p><strong>Terceros con Servicios Similares</strong></p><ul><li>Incluye cualquier servicio proporcionado por las entidades anteriores y sus empresas afiliadas</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Advertencia de Uso Comercial</p><p>Si planeas ofrecer Plannotator como parte de un servicio comercial para uso de terceros, debes obtener una licencia comercial con anticipación. La violación de este término terminará automáticamente tus derechos de uso de Plannotator en la versión actual y todas las versiones futuras.</p></div><h2 id="calendario-de-cambio-de-licencia" tabindex="-1">Calendario de Cambio de Licencia <a class="header-anchor" href="#calendario-de-cambio-de-licencia" aria-label="Permalink to &quot;Calendario de Cambio de Licencia&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Punto Temporal</th><th>Tipo de Licencia</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Actual - 2030-01-01</strong></td><td>BSL 1.1</td><td>Licencia de código abierto restringida</td></tr><tr><td><strong>Desde 2030-01-01</strong></td><td>Apache 2.0</td><td>Completamente de código abierto, sin restricciones comerciales</td></tr></tbody></table><h3 id="¿que-sucedera-despues-del-cambio" tabindex="-1">¿Qué Sucederá Después del Cambio? <a class="header-anchor" href="#¿que-sucedera-despues-del-cambio" aria-label="Permalink to &quot;¿Qué Sucederá Después del Cambio?&quot;">​</a></h3><p>A partir del 1 de enero de 2030, Plannotator se convertirá automáticamente a <strong>Apache License 2.0</strong>. Esto significa:</p><ul><li>✅ Todas las restricciones comerciales se eliminarán</li><li>✅ Se podrá usar libremente para cualquier propósito comercial</li><li>✅ Se podrá integrar en cualquier servicio SaaS</li><li>✅ Cumple con los estándares de licencias de código abierto permisivas</li></ul><h2 id="licencia-comercial" tabindex="-1">Licencia Comercial <a class="header-anchor" href="#licencia-comercial" aria-label="Permalink to &quot;Licencia Comercial&quot;">​</a></h2><p>Si necesitas usar Plannotator sin cumplir con las restricciones de BSL (por ejemplo, para servicios de planificación, contexto o aprobación), puedes:</p><ol><li><p><strong>Comprar una Licencia Comercial</strong></p><ul><li>Adquirir de backnotprop o sus distribuidores autorizados</li><li>Obtener derechos de uso sin las restricciones de BSL</li></ul></li><li><p><strong>Contactar al Licenciante</strong></p><ul><li>Enviar correo a: backnotprop</li><li>Explicar tu escenario de uso y necesidades</li></ul></li></ol><h2 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h2><h3 id="¿puedo-usar-plannotator-dentro-de-mi-empresa" tabindex="-1">¿Puedo usar Plannotator dentro de mi empresa? <a class="header-anchor" href="#¿puedo-usar-plannotator-dentro-de-mi-empresa" aria-label="Permalink to &quot;¿Puedo usar Plannotator dentro de mi empresa?&quot;">​</a></h3><p><strong>Sí.</strong> BSL permite explícitamente que tú y tus empleados, contratistas independientes usen Plannotator para desarrollo interno, pruebas y despliegue. La restricción solo se aplica a escenarios donde se proporcionan servicios a <strong>terceros</strong> (no empleados ni contratistas).</p><h3 id="¿puedo-desarrollar-mi-propio-producto-basado-en-plannotator" tabindex="-1">¿Puedo desarrollar mi propio producto basado en Plannotator? <a class="header-anchor" href="#¿puedo-desarrollar-mi-propio-producto-basado-en-plannotator" aria-label="Permalink to &quot;¿Puedo desarrollar mi propio producto basado en Plannotator?&quot;">​</a></h3><p><strong>Sí, con condiciones.</strong> Si tu producto es:</p><ul><li>Herramienta interna: ✅ Permitido</li><li>Proyecto personal: ✅ Permitido</li><li>Proyecto de código abierto: ✅ Permitido (conservando la licencia BSL)</li><li>Producto comercial: ❓ Se requiere evaluar si pertenece a &quot;servicios de planificación, contexto o aprobación&quot;</li></ul><h3 id="mi-empresa-es-un-proveedor-saas-¿puede-usarlo" tabindex="-1">Mi empresa es un proveedor SaaS, ¿puede usarlo? <a class="header-anchor" href="#mi-empresa-es-un-proveedor-saas-¿puede-usarlo" aria-label="Permalink to &quot;Mi empresa es un proveedor SaaS, ¿puede usarlo?&quot;">​</a></h3><p><strong>Se requiere licencia comercial.</strong> Si tu producto SaaS ofrece las funciones de Plannotator a clientes para su uso (incluso como parte de las funcionalidades), esto se considera un servicio comercial restringido y debes adquirir una licencia comercial.</p><h3 id="¿podre-usar-plannotator-para-cualquier-proposito-despues-de-2030" tabindex="-1">¿Podré usar Plannotator para cualquier propósito después de 2030? <a class="header-anchor" href="#¿podre-usar-plannotator-para-cualquier-proposito-despues-de-2030" aria-label="Permalink to &quot;¿Podré usar Plannotator para cualquier propósito después de 2030?&quot;">​</a></h3><p><strong>Sí.</strong> A partir de la fecha de cambio, Plannotador adoptará la licencia Apache 2.0, todas las restricciones comerciales se eliminarán y podrás usarlo libremente para cualquier propósito.</p><h2 id="texto-completo-de-la-licencia" tabindex="-1">Texto Completo de la Licencia <a class="header-anchor" href="#texto-completo-de-la-licencia" aria-label="Permalink to &quot;Texto Completo de la Licencia&quot;">​</a></h2><p>Para el texto completo de Business Source License 1.1, consulta el archivo <code>LICENSE</code> en el directorio raíz del proyecto.</p><h2 id="informacion-de-contacto" tabindex="-1">Información de Contacto <a class="header-anchor" href="#informacion-de-contacto" aria-label="Permalink to &quot;Información de Contacto&quot;">​</a></h2><p>Para licencias comerciales u otras preguntas, contacta:</p><ul><li><strong>Licenciante</strong>: backnotprop</li><li><strong>Repositorio del Proyecto</strong>: <a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima Lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima Lección&quot;">​</a></h2><blockquote><p>En la próxima lección veremos las <strong><a href="./../../changelog/release-notes/">Notas de Lanzamiento</a></strong>.</p><p>Verás:</p><ul><li>Historial de versiones de Plannotator</li><li>Nuevas funciones y mejoras en cada versión</li><li>Correcciones importantes de errores</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del Código Fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del Archivo</th><th>Número de Línea</th></tr></thead><tbody><tr><td>Declaración de Licencia</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>Texto Completo de la Licencia</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>Información Clave</strong>:</p><ul><li>Tipo de licencia: Business Source License 1.1 (BSL)</li><li>Titular de derechos: backnotprop (c) 2025</li><li>Fecha de cambio: 2030-01-01</li><li>Licencia posterior al cambio: Apache License, Version 2.0</li><li>Restricción principal: No usar para servicios de planificación, contexto o aprobación</li></ul></details>',47)])])}const h=a(t,[["render",n]]);export{m as __pageData,h as default};
